const d = $input.item.json.body;

// Hàm format số tiền thành chuẩn VN
const fmt = (n) => {
    if (!n) return '....................';
    return new Intl.NumberFormat('vi-VN').format(n);
};

d.giaThueFormatted = fmt(d.giaThue);

// TÍNH TIỀN & TẠO QR
const tienPhaiDong = Number(d.giaThue || 0);
d.tienPhaiDongFormatted = fmt(tienPhaiDong);

// ƯU TIÊN DÙNG CHUỖI VIETQR ĐỂ QUÉT BẰNG APP NGÂN HÀNG
if (d.payosQr) {
    d.qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=${encodeURIComponent(d.payosQr)}`;
} else if (d.payosUrl) {
    d.qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=${encodeURIComponent(d.payosUrl)}`;
} else {
    d.qrUrl = 'https://payos.vn/error';
}


// Lấy ngày tháng năm hiện tại
const today = new Date();
const day = String(today.getDate()).padStart(2, '0');
const month = String(today.getMonth() + 1).padStart(2, '0');
const year = today.getFullYear();

d.soThangText = (d.soThang || 12) + ' tháng';

// Khung HTML giữ nguyên format MS Word của ông, chỉ bỏ dòng Tiền cọc
d.htmlContract = `<!DOCTYPE html>
<html lang="vi">
<head>
<meta charset="UTF-8">
<style>
  * { box-sizing: border-box; }
  body { 
    font-family: "Times New Roman", Times, serif; 
    font-size: 14pt; 
    line-height: 1.3; 
    margin: 40px; 
    color: #000; 
  }

  /* Các class tiện ích */
  .center { text-align: center !important; }
  .right { text-align: right !important; }
  .bold { font-weight: bold; }
  .italic { font-style: italic; }
  .uppercase { text-transform: uppercase; }
  .underline { text-decoration: underline; }

  /* FIX LỖI GIÃN CHỮ: Chuyển mặc định về căn trái, chỉ justify đoạn văn dài */
  .justify-text { text-align: justify; } 

  h1 { font-size: 14pt; margin: 0; padding: 0; }
  h2 { font-size: 16pt; margin: 20px 0 15px 0; padding: 0; }

  /* Ép tất cả thẻ p căn trái để không bị kéo giãn chữ */
  p { margin: 6px 0; text-align: left; } 

  .indent { padding-left: 20px; }
  .indent-more { padding-left: 40px; }

  /* CSS CHO PHẦN CHỮ KÝ */
  .signatures { display: flex; justify-content: space-between; margin-top: 40px; }
  .sig-box { width: 45%; text-align: center; }
  .spacing-bottom { margin-bottom: 10px; }

  /* STYLE CHỮ KÝ VIẾT TAY (Mực xanh, nghiêng, đổ bóng nhẹ) */
  .handwritten {
    font-family: "Brush Script MT", "Lucida Handwriting", cursive;
    font-size: 30pt;
    color: #1e3a8a; 
    display: block;
    transform: rotate(-4deg);
    margin: 15px 0;
    text-shadow: 1px 1px 2px rgba(0,0,0,0.1);
  }
  /* STYLE CON DẤU XÁC THỰC (Mực đỏ mộc) */
  .admin-seal {
    color: #dc2626;
    font-size: 10pt;
    font-weight: bold;
    border: 2px solid #dc2626;
    padding: 3px 8px;
    display: inline-block;
    border-radius: 4px;
    transform: rotate(8deg);
    margin-bottom: -10px;
  }
</style>
</head>
<body>
  <div class="center">
    <h1 class="bold uppercase">CỘNG HÒA XÃ HỘI CHỦ NGHĨA VIỆT NAM</h1>
    <p class="bold underline center">Độc lập – Tự do – Hạnh phúc</p>
  </div>

  <h2 class="center bold uppercase">HỢP ĐỒNG THUÊ PHÒNG TRỌ</h2>
  <div class="indent">
    <p>Hôm nay, ngày ${day} tháng ${month} năm ${year}; tại địa chỉ: ..........................</p>
    <p>Chúng tôi gồm:..........................................................................</p>
  </div>
  <p class="bold">1. Đại diện bên cho thuê phòng trọ (Bên A):</p>
  <div class="indent">
      <p>Ông/bà: <b>Huỳnh Ngọc Huy</b> <span style="float:right">Sinh ngày: ....................................</span></p>
      <p>Nơi đăng ký HK:......................................................................................................................</p>
      <p>CMND/CCCD số: .................................... cấp ngày .......................... tại: ...................................................</p>
      <p>Số điện thoại: .......................................................................</p>
  </div>

  <p class="bold" style="margin-top: 10px;">2. Bên thuê phòng trọ (Bên B):</p>
  <div class="indent">
      <p>Ông/bà: <b>${d.hoTen || '........................................'}</b> <span style="float:right">Sinh ngày: ${d.ngaySinh || '....................................'}</span></p>
      <p>Nơi đăng ký HK thường trú: ${d.thuongTru || '...................................................................................................'}</p>
      <p>Số CMND/CCCD: <b>${d.soCccd || '....................................'}</b> cấp ngày: ${d.ngayCap || '....................'} tại: ${d.noiCap || '....................'}</p>
      <p>Số điện thoại: <b>${d.sdt || '................................................'}</b></p>
  </div>

  <div class="indent" style="margin-top: 15px;">
      <p class="justify-text">Sau khi bàn bạc trên tinh thần dân chủ, hai bên cùng có lợi, cùng thống nhất như sau:</p>
      <p class="justify-text">Bên A đồng ý cho bên B thuê 01 phòng ở tại địa chỉ: ................................................................................</p>

      <div class="indent">
          <p>- Phòng số: <b>${d.phong || '...........'}</b></p>
          <p>- Giá thuê: <b>${d.giaThueFormatted} đ/tháng</b></p>
          <p>- Hình thức thanh toán: ....................................................................................................................</p>
          <p>- Tiền điện: 3.500 đ/kwh tính theo chỉ số công tơ, thanh toán vào cuối các tháng.</p>
          <p>- Tiền nước: 100.000 đ/người thanh toán vào đầu các tháng.</p>
          <p>- Thời hạn thuê: <b>${d.soThangText}</b>, bắt đầu tính tiền từ ngày: <b>${d.ngayBatDau || '....................'}</b></p>
      </div>
  </div>

  <p class="bold uppercase underline" style="margin-top: 20px;">TRÁCH NHIỆM CỦA CÁC BÊN</p>

  <p class="bold">* Trách nhiệm của bên A:</p>
  <div class="indent">
      <p class="justify-text">- Tạo mọi điều kiện thuận lợi để bên B thực hiện theo hợp đồng.</p>
      <p class="justify-text">- Cung cấp nguồn điện, nước, wifi cho bên B sử dụng.</p>
  </div>

  <p class="bold" style="margin-top: 10px;">* Trách nhiệm của bên B:</p>
  <div class="indent">
      <p class="justify-text">- Thanh toán đầy đủ các khoản tiền theo đúng thỏa thuận.</p>
      <p class="justify-text">- Bảo quản các trang thiết bị và cơ sở vật chất của bên A trang bị cho ban đầu (làm hỏng phải sửa, mất phải đền).</p>
      <p class="justify-text">- Không được tự ý sửa chữa, cải tạo cơ sở vật chất khi chưa được sự đồng ý của bên A.</p>
      <p class="justify-text">- Giữ gìn vệ sinh trong và ngoài khuôn viên của phòng trọ.</p>
      <p class="justify-text">- Bên B phải chấp hành mọi quy định của pháp luật Nhà nước và quy định của địa phương.</p>
      <p class="justify-text">- Nếu bên B cho khách ở qua đêm thì phải báo và được sự đồng ý của chủ nhà đồng thời phải chịu trách nhiệm về các hành vi vi phạm pháp luật của khách trong thời gian ở lại.</p>
  </div>

  <p class="bold uppercase underline" style="margin-top: 20px;">TRÁCH NHIỆM CHUNG</p>
  <div class="indent">
      <p class="justify-text">- Hai bên phải tạo điều kiện cho nhau thực hiện hợp đồng.</p>
      <p class="justify-text">- Trong thời gian hợp đồng còn hiệu lực nếu bên nào vi phạm các điều khoản đã thỏa thuận thì bên còn lại có quyền đơn phương chấm dứt hợp đồng; nếu sự vi phạm hợp đồng đó gây tổn thất cho bên bị vi phạm hợp đồng thì bên vi phạm hợp đồng phải bồi thường thiệt hại.</p>
      <p class="justify-text">- Một trong hai bên muốn chấm dứt hợp đồng trước thời hạn thì phải báo trước cho bên kia ít nhất 30 ngày và hai bên phải có sự thống nhất.</p>
      <p class="justify-text">- Bên nào vi phạm điều khoản chung thì phải chịu trách nhiệm trước pháp luật.</p>
      <p class="justify-text">- Hợp đồng được lập thành 02 bản có giá trị pháp lý như nhau, mỗi bên giữ một bản.</p>
  </div>

  <div class="signatures">
      <div class="sig-box">
          <p class="bold center">ĐẠI DIỆN BÊN B</p>
          <p class="italic spacing-bottom center">(Ký, ghi rõ họ tên)</p>
          <span class="handwritten">${d.hoTen || ''}</span>
          <p class="bold center">${d.hoTen || ''}</p>
      </div>
      <div class="sig-box">
          <p class="bold center">ĐẠI DIỆN BÊN A</p>
          <p class="italic spacing-bottom center">(Ký, ghi rõ họ tên)</p>
          <div class="center"><span class="admin-seal">ĐÃ XÁC THỰC</span></div>
          <span class="handwritten">Huy Huỳnh</span>
          <p class="bold center">Huỳnh Ngọc Huy</p>
      </div>
  </div>
</body>
</html>`;

return d;

// 1. Lấy chuỗi HTML từ Node tạo hợp đồng
const htmlContent = $json.htmlContract;

// 2. Ép nó thành Buffer chuẩn của Node.js
const buffer = Buffer.from(htmlContent, 'utf-8');

// 3. Đóng gói thành file binary an toàn tuyệt đối bằng hàm prepareBinaryData
const binaryData = await this.helpers.prepareBinaryData(
  buffer, 
  'index.html', 
  'text/html'
);

// 4. Truyền đi tiếp
return {
  json: $json,
  binary: {
    indexHtml: binaryData
  }
};

// 1. Chỉ định ĐÍCH DANH tên gói hàng mà Gotenberg trả về (mặc định là 'data')
const binaryKey = 'data';

// Kiểm tra xem Gotenberg có thực sự nhả file vào đây chưa
if (!$input.item.binary || !$input.item.binary[binaryKey]) {
  throw new Error("Gotenberg chưa trả file về biến 'data'. Hãy kiểm tra Node Gotenberg (Response Format phải là File).");
}

// 2. Lấy bộ đệm (Buffer) của ĐÚNG file PDF đó
const pdfBuffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);

// 3. Kiểm tra chéo xem có phải PDF xịn không
const pdfBase64 = pdfBuffer.toString('base64');
if (!pdfBase64.startsWith('JVBERi0')) {
    const errorText = pdfBuffer.toString('utf-8');
    throw new Error("Lỗi bốc nhầm file hoặc file hỏng: " + errorText.substring(0, 100));
}

// 4. Lấy lại thông tin khách hàng từ Node tạo hợp đồng
const prevData = $('Format & Tạo HTML Hợp Đồng').item.json;

// 5. Đóng gói file PDF hoàn hảo
const fileName = `Hop_Dong_Phong_${prevData.phong || 'X'}.pdf`;
const cleanPdfBinary = await this.helpers.prepareBinaryData(
  pdfBuffer, 
  fileName, 
  'application/pdf'
);

// 6. Xóa bỏ file HTML cũ đi cho nhẹ máy, chỉ truyền PDF đi tiếp
return {
  json: {
    ...prevData,
    pdfBase64: pdfBase64
  },
  binary: {
    data: cleanPdfBinary
  }
};

