// 1. Lấy toàn bộ dữ liệu khách hàng (JSON) từ node Lấy PDF Base64
const fullData = $('Lấy PDF Base64').item.json;

// 2. Lấy file PDF (Binary) cũng từ node Lấy PDF Base64 luôn
// Vì node "Lưu PDF vào Database" ngay phía trước đã làm mất binary rồi
const pdfFile = $('Lấy PDF Base64').item.binary.data;

return {
  json: fullData,
  binary: {
    data: pdfFile
  }
};
